final:
module png_filter_selector (
    input [2:0] filter_type,
    output reg [2:0] obf_filter_code,
    output reg valid
);
    always @(*) begin
        case (filter_type)
            3'b000: begin // None
                obf_filter_code = 3'b000;
                valid = 1;
            end
            3'b001: begin // Sub
                obf_filter_code = 3'b001;
                valid = 1;
            end
            3'b010: begin // Up
                obf_filter_code = 3'b010;
                valid = 1;
            end
            3'b011: begin // Average
                obf_filter_code = 3'b011;
                valid = 1;
            end
            3'b100: begin // Paeth
                obf_filter_code = 3'b100;
                valid = 1;
            end
            default: begin // Invalid filter type
                obf_filter_code = 3'bxxx;
                valid = 0;
            end
        endcase
    end
endmodule
